[System.Convert]::FromBase64String($icons["192"]) | Set-Content -Path ".\public\logo192.png" -Encoding Byte
[System.Convert]::FromBase64String($icons["512"]) | Set-Content -Path ".\public\logo512.png" -Encoding Byte

$faviconIco = @"

"@
[System.Convert]::FromBase64String($faviconIco) | Set-Content -Path ".\public\favicon.ico" -Encoding Byte

