'@ | Set-Content -Path ".\index.html" -Encoding UTF8

# Garante registro PWA dentro do bundle do Vite
$mainPath = ".\src\main.jsx"
$main = Get-Content $mainPath -Raw
if ($main -notmatch 'pwa-register') {
  $main = 'import "./pwa-register";' + "`n" + $main
  Set-Content -Path $mainPath -Value $main -Encoding UTF8
}

@'
{
